mapper.sql:
where d.tenant_id = #{tenantId} and d.del_flag = 0
and d.process_status = #{statusCode}
and ( d.difference_no like concat('%', #{keyword}, '%') or d.related_order_no like concat('%', #{keyword}, '%') or d.difference_type like concat('%', #{keyword}, '%') or d.process_status like concat('%', #{keyword}, '%') or r.reconciliation_no like concat('%', #{keyword}, '%') or r.channel_code like concat('%', #{keyword}, '%') )
